import React, { useState, useEffect } from 'react';
import axios from 'axios'; // Asigură-te că ai importat axios
import VideoBackground from "../VideoBackground/VideoBackground";
import './StudentPage.css';
import AssignmentUpload from '../Assignments/AssignmentUpload';

interface Assignment {
    assid: number;
    asstitle: string;
    description: string;
}

const StudentPage: React.FC = () => {
    const username = localStorage.getItem('username') || 'Student';
    const [assignments, setAssignments] = useState<Assignment[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchAssignments = async () => {
            const token = localStorage.getItem('token');
            try {


                // --- PÂNĂ ATUNCI, FOLOSIM SIMULARE ---
                setAssignments([
                    { assid: 1, asstitle: "Temă Matematică", description: "Rezolvați ecuațiile din fișier." },
                    { assid: 2, asstitle: "Eseu Istorie", description: "Eseu 2 pagini despre Ștefan cel Mare." }
                ]);

            } catch (error) {
                console.error("Nu am putut încărca temele:", error);
            } finally {
                setIsLoading(false);
            }
        };

        fetchAssignments();
    }, []);

    return (
        <div className="student-page-container">
            <VideoBackground />
            <div className="content-box-student">
                <h1>Panou Student: {username}</h1>

                {isLoading ? (
                    <p>Se încarcă temele...</p>
                ) : (
                    <div className="assignments-list">
                        <h2>Temele Tale Active:</h2>
                        {assignments.length === 0 ? (
                            <p>Nu ai nicio temă activă.</p>
                        ) : (
                            assignments.map(tema => (
                                <div key={tema.assid} className="assignment-card">
                                    <h3>{tema.asstitle}</h3>
                                    <p>{tema.description}</p>

                                    {/* Componenta de upload pentru fiecare temă */}
                                    <AssignmentUpload assignmentId={tema.assid} />
                                </div>
                            ))
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default StudentPage;
